import * as React from "react";
import { RouteComponentProps, withRouter } from "react-router";
import { connect } from "react-redux";
import CodeMirrorEditor from "../CodeMirrorEditor";
import MarkdownView from "../fileView/MarkdownView";

interface IState {

}

interface IProps extends RouteComponentProps<any> {
    source?: string;
    onChange?: any;
}

const mapStateToProps = (state: any) => {
    return {
        
    }
};

const mapDispatchTpProps = {

};



class MarkdownEditor extends React.Component<IProps, IState> {

    handleMarkdownChange = (e: any) => {
        if (this.props.onChange) {
            this.props.onChange(e);
        }
    };

    render() {
        return (
            <div className="md_editor_content">
                <div className="editor-pane">
                    <CodeMirrorEditor mode="markdown" theme="monokai" value={this.props.source} onChange={this.handleMarkdownChange} />
                </div>
                <div className="result-pane">
                    <MarkdownView source={this.props.source} />
                </div>
            </div>
        );
    }
}
export default withRouter(connect(mapStateToProps, mapDispatchTpProps)(MarkdownEditor));