import * as React from "react";
import { RouteComponentProps, withRouter } from "react-router";
import { connect } from "react-redux";
import { updateWidget } from "../../actions/settingActions";
import { WidgetName_Blog_Explorer, WidgetName_Workspace_Explorer } from "../../constants/WidgetNames";
import BlogNavPanel from './BlogNavPanel';
import WorkspaceNavPanel from "./WorkspaceNavPanel";

interface IState {

}

interface IProps extends RouteComponentProps<any> {
    leftWidget: string|null;
    updateWidget: any;
}

const mapStateToProps = (state: any) => {
    return {
        leftWidget: state.setting.leftWidget
    }
};

const mapDispatchTpProps = {
    updateWidget
};

class PerspectiveLeftPanel extends React.Component<IProps, IState> {

    generateContent = () => {
        switch(this.props.leftWidget) {
            case WidgetName_Blog_Explorer:
                return <BlogNavPanel />;
            case WidgetName_Workspace_Explorer:
                return <WorkspaceNavPanel />
            default:
                return null;
        }
    };

    render() {
        return (
            <>{ this.generateContent() }</>
        );
    }
}
export default withRouter(connect(mapStateToProps, mapDispatchTpProps)(PerspectiveLeftPanel));